REFACTOR: Use lazy factory pattern with dynamic adapter resolution:
  export async function createAdapters(options: { includeShipping?: boolean } = {}) {
    const adapters: Record<string, any> = {};

    // TikTok Shop — required
    if (process.env.TIKTOK_SHOP_APP_KEY && process.env.TIKTOK_SHOP_APP_SECRET) {
      adapters.shopAdapter = new TikTokShopAdapter({...});
    } else {
      throw new Error('TikTok Shop env vars missing');
    }

    // Crawler — choose based on env
    if (process.env.CRAWLER_TYPE === 'self-hosted') {
      if (!process.env.CRAWLER_BASE_URL) throw new Error('CRAWLER_BASE_URL required for self-hosted');
      adapters.crawlerAdapter = new SelfHostedCrawlerAdapter({...});
    } else if (process.env.APIFY_API_TOKEN) {
      adapters.crawlerAdapter = new ApifyTikTokCrawlerAdapter({...});
    } else {
      throw new Error('Crawler config invalid');
    }

    // Shipping — optional
    if (options.includeShipping) {
      if (process.env.SHIPPING_TRACKER === 'self-hosted') {
        if (!process.env.SHIPPING_TRACKER_URL) throw new Error('SHIPPING_TRACKER_URL required');
        adapters.shippingAdapter = new SelfHostedShippingAdapter({...});
      } else if (process.env.AFTERSHIP_API_KEY) {
        adapters.shippingAdapter = new AfterShipTrackingAdapter({...});
      }
    }

    return adapters;
  }
  This way, missing optional vars don't crash required adapters. Call with explicit flags.

