Add optimistic locking using updated_at:
  In updateReferralStatuses():
    // Fetch with version
    const { data: referral } = await supabase
      .from('referrals')
      .select('*')
      .eq('id', id)
      .single();

    // Check conditions, compute newStatus
    const { error } = await supabase
      .from('referrals')
      .update({ status: newStatus, bonus_amount: newBonus, updated_at: NOW() })
      .eq('id', id)
      .eq('updated_at', referral.updated_at); // Optimistic lock

    if (error && error.code === 'PGRST116') {
      // Concurrent update detected, skip
      console.log('Referral was updated concurrently, skipping');
      continue;
    }
